package com.back.capstone.controller;
import com.back.capstone.dto.FileResponse;import com.back.capstone.entity.FileMetadata;import com.back.capstone.service.FileService;import java.nio.file.*;import java.util.*;import org.springframework.core.io.*;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;
@RestController @RequestMapping("/api/files") public class FileController {private final FileService files;public FileController(FileService f){files=f;}@PostMapping("/upload") ResponseEntity<List<FileResponse>> upload(Authentication a,@RequestParam("files") List<MultipartFile> f){return ResponseEntity.status(HttpStatus.CREATED).body(files.upload(a,f));}@GetMapping List<FileResponse> list(Authentication a,@RequestParam(required=false) String category){return files.list(a,category);}@GetMapping("/recent") List<FileResponse> recent(Authentication a){return files.recent(a);}@GetMapping("/search") List<FileResponse> search(Authentication a,@RequestParam String query){return files.search(a,query);}@GetMapping("/{id}") FileResponse get(Authentication a,@PathVariable Long id){return files.get(a,id);}@GetMapping("/{id}/content") ResponseEntity<Resource> content(Authentication a,@PathVariable Long id){FileMetadata f=files.owned(a,id);return ResponseEntity.ok().contentType(MediaType.parseMediaType(f.getMimeType())).body(new FileSystemResource(files.content(a,id)));}@GetMapping("/{id}/download") ResponseEntity<Resource> download(Authentication a,@PathVariable Long id){FileMetadata f=files.owned(a,id);return ResponseEntity.ok().contentType(MediaType.parseMediaType(f.getMimeType())).header(HttpHeaders.CONTENT_DISPOSITION,ContentDisposition.attachment().filename(f.getOriginalName()).build().toString()).body(new FileSystemResource(files.content(a,id)));}@DeleteMapping("/{id}") ResponseEntity<Void> delete(Authentication a,@PathVariable Long id){files.delete(a,id);return ResponseEntity.noContent().build();}}
